tests:
assert flatten({}) == {}
assert flatten({'a':1}) == {'a':1}
assert flatten({'a':{'b':[1,{'c':2}]}}) == {'a.b.0':1,'a.b.1.c':2}
assert flatten({'x':[],'y':{}}) == {}
assert flatten({'a':[True,None]}) == {'a.0':True,'a.1':None}
assert flatten({'a':{'b':{'c':{'d':'deep'}}}}) == {'a.b.c.d':'deep'}
